import { test, expect } from '@playwright/test';

test('Amazon.sg Magic Tree House Boxed Set price and add to cart', async ({ page }) => {
  // 1. Launch browser and navigate
  await page.goto('https://www.amazon.sg');

  // 2. Wait for search input to be visible
  const searchInput = page.locator('input[name="field-keywords"]');
  await expect(searchInput).toBeVisible();

  // 3. Fill search input and submit
  await searchInput.fill('Magic Tree House Boxed Set');
  await searchInput.press('Enter');

  // 4. Wait for search results and first product link to be visible
  const firstProductLink = page.locator('.s-search-results .s-result-item h2 a').first();
  await expect(firstProductLink).toBeVisible();

  // 5. Click on the first product link
  await firstProductLink.click();

  // 6. Wait for product detail page and product title
  const productTitle = page.locator('#productTitle');
  await expect(productTitle).toBeVisible();

  // 7. Read product title text
  const titleText = (await productTitle.textContent())?.trim() || '';

  // 8. Read product price
  let priceText = '';
  let priceLocator = page.locator('#priceblock_ourprice');
  if (await priceLocator.isVisible()) {
    priceText = await priceLocator.textContent();
  } else {
    priceLocator = page.locator('#priceblock_dealprice');
    if (await priceLocator.isVisible()) {
      priceText = await priceLocator.textContent();
    } else {
      priceLocator = page.locator('.a-price .a-offscreen').first();
      if (await priceLocator.isVisible()) {
        priceText = await priceLocator.textContent();
      }
    }
  }
  priceText = priceText.replace(/[^\d.,]/g, '').replace(',', '');
  const priceValue = parseFloat(priceText);

  // 9. Validate price is less than 25
  expect(priceValue).toBeLessThan(25);

  // 10. Click "Add to Cart" button
  const addToCartButton = page.locator('#add-to-cart-button');
  await expect(addToCartButton).toBeVisible();
  await addToCartButton.click();

  // 11. Wait for cart confirmation or cart count to increase
  const cartCount = page.locator('#nav-cart-count');
  const initialCartCount = parseInt((await cartCount.textContent()) || '0', 10);

  // Wait for either confirmation message or cart count to increase
  await Promise.race([
    page.locator('#huc-v2-order-row-confirm-text').waitFor({ timeout: 10000 }).catch(() => {}),
    page.waitForFunction(
      (selector, initial) => {
        const el = document.querySelector(selector);
        return el && parseInt(el.textContent || '0', 10) > initial;
      },
      '#nav-cart-count',
      initialCartCount,
      { timeout: 10000 }
    ).catch(() => {})
  ]);
});
